  1	import { Badge, Dropdown, DropdownItem, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
  2	import * as React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { FilterCompare, FilterComponent, getCompareText } from '../../../model/filters';
  5	import { usePrevious } from '../../../utils/previous-hook';
  6	
  7	export interface CompareFilterProps {
  8	  value: FilterCompare;
  9	  setValue: (newState: FilterCompare) => void;
 10	  component?: FilterComponent;
 11	}
 12	
 13	export const CompareFilter: React.FC<CompareFilterProps> = ({ value, setValue, component }) => {
 14	  const { t } = useTranslation('plugin__netobserv-plugin');
 15	  const [isOpen, setOpen] = React.useState(false);
 16	  const prevComponent = usePrevious(component);
 17	
 18	  const getText = React.useCallback((v: FilterCompare) => getCompareText(v, t), [t]);
 19	
 20	  const onSelect = React.useCallback(
 21	    (v: FilterCompare) => {
 22	      setValue(v);
 23	      setOpen(false);
 24	    },
 25	    [setValue]
 26	  );
 27	
 28	  const getItems = React.useCallback(() => {
 29	    const dropdownItems = [
 30	      <DropdownItem
 31	        key="equal"
 32	        id="equal"
 33	        component="button"
 34	        description={getText(FilterCompare.equal)}
 35	        onClick={() => onSelect(FilterCompare.equal)}
 36	      >
 37	        {FilterCompare.equal}
 38	      </DropdownItem>,
 39	      <DropdownItem
 40	        key="not-equal"
 41	        id="not-equal"
 42	        component="button"
 43	        description={getText(FilterCompare.notEqual)}
 44	        onClick={() => onSelect(FilterCompare.notEqual)}
 45	      >
 46	        {FilterCompare.notEqual}
 47	      </DropdownItem>
 48	    ];
 49	
 50	    if (component === 'number') {
 51	      dropdownItems.push(
 52	        <DropdownItem
 53	          key="more-than"
 54	          id="more-than"
 55	          component="button"
 56	          description={getText(FilterCompare.moreThanOrEqual)}
 57	          onClick={() => onSelect(FilterCompare.moreThanOrEqual)}
 58	        >
 59	          {FilterCompare.moreThanOrEqual}
 60	        </DropdownItem>
 61	      );
 62	    } else {
 63	      dropdownItems.push(
 64	        <DropdownItem
 65	          key="match"
 66	          id="match"
 67	          component="button"
 68	          description={getText(FilterCompare.match)}
 69	          onClick={() => onSelect(FilterCompare.match)}
 70	        >
 71	          {FilterCompare.match}
 72	        </DropdownItem>,
 73	        <DropdownItem
 74	          key="not-match"
 75	          id="not-match"
 76	          component="button"
 77	          description={getText(FilterCompare.notMatch)}
 78	          onClick={() => onSelect(FilterCompare.notMatch)}
 79	        >
 80	          {FilterCompare.notMatch}
 81	        </DropdownItem>
 82	      );
 83	    }
 84	    return dropdownItems;
 85	  }, [component, getText, onSelect]);
 86	
 87	  React.useEffect(() => {
 88	    // reset to equal when component change
 89	    if (prevComponent !== undefined && prevComponent !== component) {
 90	      setValue(FilterCompare.equal);
 91	    }
 92	  }, [component, prevComponent, setValue]);
 93	
 94	  return (
 95	    <Dropdown
 96	      id="filter-compare"
 97	      isOpen={isOpen}
 98	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 99	        <MenuToggle
100	          ref={toggleRef}
101	          id="filter-compare-toggle-button"
102	          badge={<Badge>{value}</Badge>}
103	          onClick={() => setOpen(!isOpen)}
104	          isExpanded={isOpen}
105	          onBlur={() => setTimeout(() => setOpen(false), 500)}
106	        >
107	          {getText(value)}
108	        </MenuToggle>
109	      )}
110	    >
111	      {getItems()}
112	    </Dropdown>
113	  );
114	};
115	
116	export default CompareFilter;

