 1	import { act, fireEvent, render, waitFor } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { FilterCompare } from '../../../../model/filters';
 5	import CompareFilter, { CompareFilterProps } from '../compare-filter';
 6	
 7	describe('<CompareFilter />', () => {
 8	  const props: CompareFilterProps = {
 9	    value: FilterCompare.equal,
10	    setValue: jest.fn(),
11	    component: 'text'
12	  };
13	
14	  it('should render component', async () => {
15	    const { container } = render(<CompareFilter {...props} />);
16	    expect(container.querySelector('#filter-compare-toggle-button')).toBeTruthy();
17	  });
18	
19	  it('should update value', async () => {
20	    const { container } = render(<CompareFilter {...props} />);
21	
22	    expect(props.setValue).toHaveBeenCalledTimes(0);
23	
24	    await act(async () => {
25	      fireEvent.click(container.querySelector('#filter-compare-toggle-button')!);
26	    });
27	    await waitFor(() => expect(document.querySelector('[id="not-equal"]')).toBeTruthy());
28	    await act(async () => {
29	      fireEvent.click(document.querySelector('[id="not-equal"]')!);
30	    });
31	    expect(props.setValue).toHaveBeenCalledWith(FilterCompare.notEqual);
32	
33	    await act(async () => {
34	      fireEvent.click(container.querySelector('#filter-compare-toggle-button')!);
35	    });
36	    await waitFor(() => expect(document.querySelector('[id="equal"]')).toBeTruthy());
37	    await act(async () => {
38	      fireEvent.click(document.querySelector('[id="equal"]')!);
39	    });
40	    expect(props.setValue).toHaveBeenCalledWith(FilterCompare.equal);
41	
42	    await act(async () => {
43	      fireEvent.click(container.querySelector('#filter-compare-toggle-button')!);
44	    });
45	    await waitFor(() => expect(document.querySelector('[id="equal"]')).toBeTruthy());
46	    expect(document.querySelector('[id="more-than"]')).toBeNull();
47	
48	    expect(props.setValue).toHaveBeenCalledTimes(2);
49	  });
50	
51	  it('number should have more than', async () => {
52	    const { container } = render(<CompareFilter {...props} component={'number'} />);
53	
54	    await act(async () => {
55	      fireEvent.click(container.querySelector('#filter-compare-toggle-button')!);
56	    });
57	    await waitFor(() => expect(document.querySelector('[id="more-than"]')).toBeTruthy());
58	    await act(async () => {
59	      fireEvent.click(document.querySelector('[id="more-than"]')!);
60	    });
61	
62	    expect(props.setValue).toHaveBeenCalledWith(FilterCompare.moreThanOrEqual);
63	  });
64	});

